<script setup lang="ts">
useSeoMeta({
  title: 'Связь с редакцией — Виноделие сегодня',
  description: 'Свяжитесь с редакцией «Виноделие сегодня». Пишите, звоните, подписывайтесь на соцсети.',
});

const form = ref({
  name: '',
  email: '',
  topic: '',
  message: '',
});

const submitted = ref(false);
const submitting = ref(false);
const error = ref('');

const topics = [
  'Предложить новость',
  'Стать автором',
  'Реклама и партнёрство',
  'Техническая поддержка',
  'Другое',
];

async function onSubmit() {
  error.value = '';
  if (!form.value.name.trim() || !form.value.email.trim() || !form.value.message.trim()) {
    error.value = 'Пожалуйста, заполните обязательные поля.';
    return;
  }
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.value.email)) {
    error.value = 'Укажите корректный email.';
    return;
  }

  submitting.value = true;
  // Demo: имитируем отправку. В проде заменить на $fetch('/api/contact', { method: 'POST', body: form.value })
  await new Promise((resolve) => setTimeout(resolve, 800));
  submitting.value = false;
  submitted.value = true;
  form.value = { name: '', email: '', topic: '', message: '' };
}
